// --- 1. CÁC HÀM HELPER ---
function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function clean(str) {
  if (!str) return "";
  if (Array.isArray(str)) return str.join(", "); 
  return String(str).replace(/[“”‘’]/g, '"').replace(/'/g, "''").replace(/[\u0000-\u0019]+/g, " ").trim();
}

function normalizeObjectKeys(obj) {
    if (!obj || typeof obj !== 'object') return {};
    const newObj = {};
    Object.keys(obj).forEach(key => {
        const cleanKey = key.toLowerCase().trim().replace(/_/g, ""); 
        newObj[cleanKey] = obj[key];
    });
    return newObj;
}

// [FIX QUAN TRỌNG] HÀM CHUYỂN ĐỔI SANG SỐ NGUYÊN (INTEGER)
function parseExperienceYears(str) {
    if (!str) return 0;
    const s = String(str).toLowerCase().trim();

    // Hàm làm tròn bắt buộc về số nguyên
    // 2.5 -> 3, 2.4 -> 2
    const toInteger = (val) => {
        return Math.round(val); 
    };

    const numberPattern = /(\d+(?:[.,]\d+)?)\s*(?:năm|year|yr|yrs|\+)/gi;

    // Ưu tiên tìm trong câu có từ khóa "tổng/total"
    const keywordIndex = s.search(/(?:tổng|total|khoảng)/i);
    if (keywordIndex !== -1) {
        const subString = s.substring(keywordIndex);
        const matchesInSubString = [...subString.matchAll(numberPattern)];
        if (matchesInSubString.length > 0) {
             const lastMatch = matchesInSubString[matchesInSubString.length - 1];
             const floatVal = parseFloat(lastMatch[1].replace(',', '.'));
             return toInteger(floatVal); // Ép về số nguyên
        }
    }

    // Tìm match cuối cùng trong chuỗi
    const allMatches = [...s.matchAll(numberPattern)];
    if (allMatches.length > 0) {
        const lastMatch = allMatches[allMatches.length - 1];
        const floatVal = parseFloat(lastMatch[1].replace(',', '.'));
        return toInteger(floatVal); // Ép về số nguyên
    }

    // Fallback: Tìm số bất kỳ hợp lý (0 < x < 80)
    const allNumbers = s.match(/(\d+(?:[.,]\d+)?)/g);
    if (allNumbers && allNumbers.length > 0) {
        for (const numStr of allNumbers) {
            const val = parseFloat(numStr.replace(',', '.'));
            if (val > 0 && val < 80) {
                return toInteger(val); // Ép về số nguyên
            }
        }
    }
    return 0; // Mặc định là 0 nếu không tìm thấy
}

// --- 2. XỬ LÝ DATA ---
const items = $input.all();
const out = [];

for (const item of items) {
  const inputJson = item.json;
  let data = {};

  if (inputJson.contact_info && (inputJson.experience || inputJson.skills)) {
      data = inputJson;
  } else if (inputJson.parsed_json) {
      data = inputJson.parsed_json;
  } else {
    const rawContent = inputJson.output || inputJson.text || JSON.stringify(inputJson);
    let jsonString = String(rawContent).replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/, '').trim();
    try { data = JSON.parse(jsonString); } catch (e) { 
        const match = jsonString.match(/\{[\s\S]*\}/);
        if (match) try { data = JSON.parse(match[0]); } catch (err) {}
    }
  }

  if (!data || !data.contact_info) continue;

  const candidateId = uuid(); 
  const timestamp = new Date().toISOString();
  const contact = data.contact_info || {};
  const candidateName = clean(contact.name || 'Unknown');
  const phone = clean(contact.phone || data.phone || "Không có SĐT");
  const rawLink = data.link_cv || data.link || "";
  const linkCV = clean(Array.isArray(rawLink) ? rawLink[0] : rawLink);

  // Xử lý chuỗi tổng kinh nghiệm thô
  let globalTotalExpString = "Không xác định";
  if (data.total) {
      if (Array.isArray(data.total) && data.total.length > 0) {
          const t = data.total[0];
          globalTotalExpString = (typeof t === 'object') ? (normalizeObjectKeys(t).totalexp || normalizeObjectKeys(t).total) : String(t);
      } else if (typeof data.total === 'object') {
          globalTotalExpString = normalizeObjectKeys(data.total).totalexp || normalizeObjectKeys(data.total).total;
      } else {
          globalTotalExpString = String(data.total);
      }
  }

  // [KẾT QUẢ] Biến này bây giờ chắc chắn là INT (Ví dụ: 3, 4, 5)
  const experienceYearsInt = parseExperienceYears(globalTotalExpString);

  // Tạo header info
  const headerInfo = `
  Name: ${candidateName}
  Phone: ${phone}              
  Link CV: ${linkCV}
  Total Experience Years: ${experienceYearsInt}
  `;

  // Payload Base
  const baseMetadata = {
    candidate_id: candidateId,
    candidate_name: candidateName,
    candidate_email: clean(contact.email),
    candidate_phone: phone, 
    link_cv: linkCV, 
    imported_at: timestamp,
    global_total_experience: globalTotalExpString,
    experience_years: experienceYearsInt // <-- Số nguyên được lưu vào đây
  };

  // 1. SKILLS
  if (data.skills && Array.isArray(data.skills) && data.skills.length > 0) {
      const allSkillsString = data.skills.join(", ");
      const txt = `${headerInfo} Candidate Skills Set: ${allSkillsString}. This candidate is proficient in: ${allSkillsString}.`;

      out.push({
        json: {
          id: uuid(),
          text: txt,
          payload: {
            ...baseMetadata,
            key: 'skill_set',
            type: 'skill',
            skills_list: data.skills,
            text: txt
          }
        }
      });
  }

  // 2. EXPERIENCE
  if (data.experience && Array.isArray(data.experience)) {
    data.experience.forEach((exp) => {
      const normExp = normalizeObjectKeys(exp);
      const localDuration = normExp.total || normExp.duration || null;
      let expStr = "";
      if (localDuration) expStr += `Role Duration: ${localDuration}.`;

      const desc = exp.description || "";
      const sentences = desc.split(/(?:\. |\.\n|\n+)/).map(s => s.trim()).filter(s => s.length > 5);

      const chunkPayload = {
          ...baseMetadata, 
          key: 'experience',
          company: exp.company,
          role: exp.role
      };

      if (sentences.length > 0) {
        sentences.forEach((sentence) => {
           const txt = `${headerInfo} Work Experience: ${exp.role} at ${exp.company}. ${expStr} Detail: ${sentence}.`;
           out.push({ json: { id: uuid(), text: txt, payload: { ...chunkPayload, text: txt } } });
        });
      } else {
        const txt = `${headerInfo} Work Experience: ${exp.role} at ${exp.company}. ${expStr}`;
        out.push({ json: { id: uuid(), text: txt, payload: { ...chunkPayload, text: txt } } });
      }
    });
  }

  // 3. EDUCATION
  if (data.education && Array.isArray(data.education)) {
      data.education.forEach((edu) => {
          const school = clean(edu.school || edu.institution);
          const major = clean(edu.major || edu.degree);
          const time = clean(edu.time || edu.year);

          if (school || major) {
              const txt = `${headerInfo} Education: ${major} at ${school}. Period: ${time}.`;
              out.push({
                  json: {
                      id: uuid(),
                      text: txt,
                      payload: {
                          ...baseMetadata,
                          key: 'education',
                          type: 'education',
                          school: school,
                          major: major,
                          time: time,
                          text: txt
                      }
                  }
              });
          }
      });
  }

  // 4. CERTIFICATION
  if (data.certification && Array.isArray(data.certification)) {
      data.certification.forEach((cert) => {
          let certName = "";
          let org = "";
          let time = "";
          if (typeof cert === 'string') {
              certName = clean(cert);
          } else {
              certName = clean(cert.name || cert.title);
              org = clean(cert.organization || cert.issuer);
              time = clean(cert.time || cert.date);
          }
          if (certName) {
              const txt = `${headerInfo} Certification: ${certName}${org ? ' from ' + org : ''}${time ? ' (' + time + ')' : ''}.`;
              out.push({
                  json: {
                      id: uuid(),
                      text: txt,
                      payload: {
                          ...baseMetadata,
                          key: 'certification',
                          type: 'certificate',
                          certificate: certName,
                          organization: org,
                          time: time,
                          text: txt
                      }
                  }
              });
          }
      });
  }
}

if (out.length === 0) return [{ json: { warning: "No valid vectors created." } }];
return out;

// Lấy data từ 2 node trước
const fmtItems = $items('Fn_Format');          // Node chứa text + payload
const embItems = $items('OpenAI Embedding');   // Node chứa vector

const points = [];

// Dùng Math.min để an toàn
const count = Math.min(fmtItems.length, embItems.length);

for (let i = 0; i < count; i++) {
  const f = fmtItems[i].json; // Data gốc
  const e = embItems[i].json; // Vector

  // 1. TÌM VECTOR (Logic bắt lỗi vector như cũ)
  const vector = e.embedding 
              || (e.data && e.data[0] ? e.data[0].embedding : null)
              || e.vector; 

  if (vector) {
     // Lấy dữ liệu từ payload hoặc metadata
     const sourceData = f.payload || f.metadata || {}; 

     // 2. TẠO PAYLOAD
     // Copy toàn bộ dữ liệu gốc (candidate_id, candidate_name, type...)
     const payload = { ...sourceData };

     // 3. XỬ LÝ LÀM SẠCH (Loại bỏ trường thừa)
     // Xóa các trường ngắn nếu chúng vô tình tồn tại
     delete payload.name;
     delete payload.email;
     delete payload.phone;
     delete payload.text_content; 

     // 4. ĐẢM BẢO CÁC TRƯỜNG QUAN TRỌNG
     // Đảm bảo link_cv luôn tồn tại (nếu null thì thành chuỗi rỗng)
     payload.link_cv = sourceData.link_cv || "";

     // Đảm bảo trường 'text' tồn tại (đây là nội dung chính để RAG đọc)
     // Nếu node trước trả về 'text' thì giữ nguyên, nếu không thì lấy từ f.text
     payload.text = sourceData.text || f.text || "";

     points.push({
       id: f.id,       // UUID
       vector: vector, // Vector Array
       payload: payload
     });
  }
}

// Kiểm tra debug
if (points.length === 0) {
  return [{
    json: {
      error: "Không tìm thấy Vector nào.",
      debug_check: {
        has_payload: !!fmtItems[0].json.payload
      }
    }
  }];
}

// Trả về format chuẩn
return [
  {
    json: { points }
  }
];

